import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Scale } from 'lucide-react';

export default function Navbar() {
  const location = useLocation();
  const active = (path) => location.pathname === path ? 'active' : '';

  return (
    <nav className="navbar">
      <Link to="/" className="navbar-brand">
        <Scale size={22} />
        Nyaya<span>Setu</span>
      </Link>
      <div className="navbar-links">
        <Link to="/"           className={active('/')}>Home</Link>
        <Link to="/analyze"    className={active('/analyze')}>Analyze Document</Link>
        <Link to="/compliance" className={active('/compliance')}>BNS Compliance</Link>
        <Link to="/evidence"   className={active('/evidence')}>Evidence Certificate</Link>
      </div>
    </nav>
  );
}
